use std::{convert::Infallible,path::{Path,PathBuf}};use core_nomos::MacroPackage;use kameo::{Actor,actor::{ActorRef,Spawn},message::{Context,Message}};use name_table::NameTable;use signal_nomos::{Reply,Request,Rejection};use signal_sema_storage::{DocumentKey,DocumentKind,DocumentPayload,NameTableBytes,NomosPackage,Reply as SReply,Request as SRequest,SlotIdentifier};use tokio::{io::{AsyncReadExt,AsyncWriteExt},net::UnixStream};
#[derive(Debug,thiserror::Error)]pub enum Error{#[error("io: {0}")]Io(#[from]std::io::Error),#[error("engine: {0}")]Engine(String),#[error("actor: {0}")]Actor(String)}type Result<T>=std::result::Result<T,Error>;
async fn exchange(p:&Path,q:&SRequest)->Result<SReply>{let mut s=UnixStream::connect(p).await?;let b=signal_sema_storage::Wire::encode_request(q).map_err(|e|Error::Engine(e.to_string()))?;s.write_u32_le(b.len()as u32).await?;s.write_all(&b).await?;let n=s.read_u32_le().await?as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;rkyv::from_bytes::<SReply,rkyv::rancor::Error>(&b).map_err(|e|Error::Engine(e.to_string()))}
pub struct SemaPlane{socket:PathBuf,writes:u64}impl Actor for SemaPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}pub struct Store(pub SRequest);impl Message<Store> for SemaPlane{type Reply=Result<SReply>;async fn handle(&mut self,m:Store,_:&mut Context<Self,Self::Reply>)->Self::Reply{self.writes+=1;exchange(&self.socket,&m.0).await}}
pub struct NexusPlane{sema:ActorRef<SemaPlane>,applied:u64}impl Actor for NexusPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}pub struct Dispatch(pub Request);impl Message<Dispatch> for NexusPlane{type Reply=Result<Reply>;async fn handle(&mut self,m:Dispatch,_:&mut Context<Self,Self::Reply>)->Self::Reply{self.applied+=1;match m.0{Request::Transform{scope,schema,output_slot}=>{let fetched=self.sema.ask(Store(SRequest::HashFetch{hash:schema})).send().await.map_err(|e|Error::Actor(e.to_string()))?;let SReply::Document(Some(document))=fetched else{return Ok(Reply::Rejected(Rejection::SchemaNotFound))};let DocumentPayload::TypeSchema{schema,names}=document.payload else{return Ok(Reply::Rejected(Rejection::WrongDocumentKind))};let names=NameTable::from_archive_bytes(&names.0).map_err(|e|Error::Engine(e.to_string()))?;let lowering=MacroPackage::wire_fixture().apply(&schema,&names).map_err(|e|Error::Engine(e.to_string()))?;let logo_names=NameTableBytes(lowering.names.to_archive_bytes().map_err(|e|Error::Engine(e.to_string()))?.to_vec());let items=lowering.items.iter().map(|item|{let bytes=rkyv::to_bytes::<rkyv::rancor::Error>(item).map_err(|e|Error::Engine(e.to_string()))?;rkyv::from_bytes::<wire_core_logos::CoreItem,rkyv::rancor::Error>(&bytes).map_err(|e|Error::Engine(e.to_string()))}).collect::<Result<Vec<_>>>()?;let _=self.sema.ask(Store(SRequest::Store{key:DocumentKey{scope,kind:DocumentKind::Nomos,slot:SlotIdentifier(0)},payload:DocumentPayload::Nomos(NomosPackage::WireFixture)})).send().await.map_err(|e|Error::Actor(e.to_string()))?;let stored=self.sema.ask(Store(SRequest::Store{key:DocumentKey{scope,kind:DocumentKind::Logos,slot:output_slot},payload:DocumentPayload::Logos{items,names:logo_names}})).send().await.map_err(|e|Error::Actor(e.to_string()))?;Ok(match stored{SReply::Stored(s)=>Reply::Transformed(s),_=>Reply::Rejected(Rejection::StorageFailed)})},Request::List{scope}=>{let r=self.sema.ask(Store(SRequest::List{scope,kind:Some(DocumentKind::Nomos)})).send().await.map_err(|e|Error::Actor(e.to_string()))?;Ok(match r{SReply::Listed(v)=>Reply::Listed(v),_=>Reply::Rejected(Rejection::StorageFailed)})},Request::Subscribe{scope}=>{let r=self.sema.ask(Store(SRequest::Subscribe{scope,kind:Some(DocumentKind::Logos)})).send().await.map_err(|e|Error::Actor(e.to_string()))?;Ok(match r{SReply::Subscribed{..}=>Reply::Subscribed,_=>Reply::Rejected(Rejection::StorageFailed)})}}}}
pub struct SignalPlane{nexus:ActorRef<NexusPlane>,admitted:u64}impl Actor for SignalPlane{type Args=Self;type Error=Infallible;async fn on_start(a:Self::Args,_:ActorRef<Self>)->std::result::Result<Self,Self::Error>{Ok(a)}}impl Message<Dispatch> for SignalPlane{type Reply=Result<Reply>;async fn handle(&mut self,m:Dispatch,_:&mut Context<Self,Self::Reply>)->Self::Reply{self.admitted+=1;self.nexus.ask(m).send().await.map_err(|e|Error::Actor(e.to_string()))}}
#[derive(Clone)]pub struct Runtime{signal:ActorRef<SignalPlane>}impl Runtime{pub fn new(socket:PathBuf)->Self{let sema=SemaPlane::spawn(SemaPlane{socket,writes:0});let nexus=NexusPlane::spawn(NexusPlane{sema,applied:0});Self{signal:SignalPlane::spawn(SignalPlane{nexus,admitted:0})}}pub async fn request(&self,q:Request)->Result<Reply>{self.signal.ask(Dispatch(q)).send().await.map_err(|e|Error::Actor(e.to_string()))}}
